class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right
def serialize(root: TreeNode) -> str:
    vals = []
    def pre(node):
        if not node:
            vals.append('#')
            return
        vals.append(str(node.val))
        pre(node.left)
        pre(node.right)
    pre(root)
    return ' '.join(vals)
def deserialize(data: str) -> TreeNode:
    it = iter(data.split())
    def build():
        val = next(it)
        if val == '#':
            return None
        node = TreeNode(int(val))
        node.left = build()
        node.right = build()
        return node
    return build()

